/**
 * เติม prefix ให้ทุก id/url(#)/href="#" ของ SVG เพื่อกัน id ชนเมื่อ render หลาย instance
 * (ใช้กับ inner SVG ที่ inject ผ่าน dangerouslySetInnerHTML)
 */
function namespaceSvgIds(svg: string, prefix: string): string {
  return svg
    .replaceAll(/id="([a-z]+)"/g, `id="${prefix}-$1"`)
    .replaceAll(/url\(#([a-z]+)\)/g, `url(#${prefix}-$1)`)
    .replaceAll(/href="#([a-z]+)"/g, `href="#${prefix}-$1"`);
}

