/** โลโก้ Google (gradient G) — inject ผ่าน dangerouslySetInnerHTML เพราะ gradient/filter เยอะเกินจะเขียน JSX */
export function GoogleIcon({
  className,
}: {
  readonly className?: string;
}) {
  const uid = useId().replaceAll(/[^a-zA-Z0-9]/g, "");
  return (
    <svg
      viewBox="0 0 268.152 273.883"
      xmlns="http://www.w3.org/2000/svg"
      className={className}
      aria-hidden="true"
      dangerouslySetInnerHTML={{ __html: namespaceSvgIds(GOOGLE_INNER, uid) }}
    />
  );
}

